import React, { useState, useEffect } from "react";
import axios from "axios";
import { Toaster, toast } from "react-hot-toast";
import {
  MapPin,
  Clock,
  Users,
  AlertTriangle,
  ThumbsUp,
  Send,
  RefreshCw,
  Activity,
} from "lucide-react";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

function App() {
  const [centers, setCenters] = useState([]);
  const [selectedCenter, setSelectedCenter] = useState(null);
  const [reports, setReports] = useState([]);
  const [currentStatus, setCurrentStatus] = useState(null);
  const [stats, setStats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showReportForm, setShowReportForm] = useState(false);
  const [reportData, setReportData] = useState({
    crowd_level: "moderate",
    wait_time: 15,
    reporter_name: "",
  });

  // Fetch centers on load
  useEffect(() => {
    fetchCenters();
    fetchStats();

    // Auto-refresh every 60 seconds
    const interval = setInterval(() => {
      if (selectedCenter) {
        fetchCenterStatus(selectedCenter.id);
        fetchReports(selectedCenter.id);
      }
      fetchStats();
    }, 60000);

    return () => clearInterval(interval);
  }, [selectedCenter]);

  const fetchCenters = async () => {
    try {
      const response = await axios.get(`${API_URL}/centers`);
      setCenters(response.data);
      if (response.data.length > 0 && !selectedCenter) {
        setSelectedCenter(response.data[0]);
      }
      setLoading(false);
    } catch (error) {
      toast.error("Failed to load centers");
      console.error(error);
    }
  };

  const fetchCenterStatus = async (centerId) => {
    try {
      const response = await axios.get(`${API_URL}/centers/${centerId}/status`);
      setCurrentStatus(response.data);
    } catch (error) {
      console.error("Failed to fetch status");
    }
  };

  const fetchReports = async (centerId) => {
    try {
      const response = await axios.get(
        `${API_URL}/centers/${centerId}/reports`,
      );
      setReports(response.data);
    } catch (error) {
      console.error("Failed to fetch reports");
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_URL}/stats`);
      setStats(response.data);
    } catch (error) {
      console.error("Failed to fetch stats");
    }
  };

  const handleCenterSelect = (center) => {
    setSelectedCenter(center);
    fetchCenterStatus(center.id);
    fetchReports(center.id);
  };

  const handleSubmitReport = async (e) => {
    e.preventDefault();

    try {
      await axios.post(`${API_URL}/reports`, {
        center_id: selectedCenter.id,
        ...reportData,
      });

      toast.success("Report submitted! Others can now verify it.");
      setShowReportForm(false);
      fetchReports(selectedCenter.id);
      fetchCenterStatus(selectedCenter.id);

      // Reset form
      setReportData({
        crowd_level: "moderate",
        wait_time: 15,
        reporter_name: "",
      });
    } catch (error) {
      toast.error("Failed to submit report");
    }
  };

  const handleVerifyReport = async (reportId) => {
    try {
      await axios.post(`${API_URL}/reports/${reportId}/verify`);
      toast.success("Thanks for verifying!");
      fetchReports(selectedCenter.id);
      fetchCenterStatus(selectedCenter.id);
    } catch (error) {
      if (error.response?.status === 400) {
        toast.error("You already verified this report");
      } else {
        toast.error("Failed to verify");
      }
    }
  };

  const getCrowdColor = (level) => {
    switch (level) {
      case "quiet":
        return "bg-green-100 text-green-800";
      case "moderate":
        return "bg-yellow-100 text-yellow-800";
      case "busy":
        return "bg-orange-100 text-orange-800";
      case "very_busy":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getCrowdIcon = (level) => {
    switch (level) {
      case "quiet":
        return "😊";
      case "moderate":
        return "😐";
      case "busy":
        return "😕";
      case "very_busy":
        return "😫";
      default:
        return "❓";
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <RefreshCw className="w-8 h-8 animate-spin text-blue-500" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Toaster position="top-right" />

      {/* Header */}
      <header className="bg-blue-600 text-white shadow-lg">
        <div className="container mx-auto px-4 py-6">
          <h1 className="text-3xl font-bold flex items-center gap-2">
            <Activity className="w-8 h-8" />
            M-Tag Rush Checker
          </h1>
          <p className="text-blue-100 mt-2">
            Real-time crowd updates from people like you
          </p>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">
        {/* Stats Overview */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          {stats.map((stat, index) => (
            <div key={index} className="bg-white rounded-lg shadow p-4">
              <h3 className="font-semibold text-gray-700">{stat.name}</h3>
              <div className="mt-2 flex justify-between items-center">
                <span className="text-2xl font-bold">
                  {stat.avg_wait_time
                    ? `${Math.round(stat.avg_wait_time)} min`
                    : "N/A"}
                </span>
                <span
                  className={`px-2 py-1 rounded text-sm ${
                    stat.rush_count > 5
                      ? "bg-red-100 text-red-800"
                      : "bg-green-100 text-green-800"
                  }`}
                >
                  {stat.rush_count} reports today
                </span>
              </div>
            </div>
          ))}
        </div>

        {/* Two Column Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Centers List */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow">
              <div className="p-4 border-b">
                <h2 className="font-semibold text-lg flex items-center gap-2">
                  <MapPin className="w-5 h-5" />
                  M-Tag Centers
                </h2>
              </div>
              <div className="divide-y">
                {centers.map((center) => (
                  <button
                    key={center.id}
                    onClick={() => handleCenterSelect(center)}
                    className={`w-full text-left p-4 hover:bg-gray-50 transition ${
                      selectedCenter?.id === center.id
                        ? "bg-blue-50 border-l-4 border-blue-500"
                        : ""
                    }`}
                  >
                    <h3 className="font-medium">{center.name}</h3>
                    <p className="text-sm text-gray-600 mt-1">
                      {center.address}
                    </p>
                    <div className="flex items-center gap-2 mt-2 text-xs text-gray-500">
                      <Clock className="w-3 h-3" />
                      {center.hours}
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Selected Center Details */}
          {selectedCenter && (
            <div className="lg:col-span-2 space-y-6">
              {/* Current Status Card */}
              <div className="bg-white rounded-lg shadow p-6">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h2 className="text-xl font-bold">{selectedCenter.name}</h2>
                    <p className="text-gray-600 text-sm mt-1">
                      {selectedCenter.address}
                    </p>
                  </div>
                  <button
                    onClick={() => setShowReportForm(!showReportForm)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition flex items-center gap-2"
                  >
                    <Send className="w-4 h-4" />
                    Report Current Rush
                  </button>
                </div>

                {/* Current Status */}
                {currentStatus && currentStatus.crowd_level !== "unknown" && (
                  <div className="bg-gray-50 rounded-lg p-4 mb-4">
                    <h3 className="text-sm font-medium text-gray-500 mb-2">
                      Current Status
                    </h3>
                    <div className="flex items-center gap-4">
                      <span
                        className={`px-3 py-1 rounded-full text-sm font-medium ${getCrowdColor(currentStatus.crowd_level)}`}
                      >
                        {getCrowdIcon(currentStatus.crowd_level)}{" "}
                        {currentStatus.crowd_level.replace("_", " ")}
                      </span>
                      <span className="text-gray-600">
                        Wait time:{" "}
                        <strong>{currentStatus.wait_time} minutes</strong>
                      </span>
                      <span className="text-xs text-gray-400">
                        Reported{" "}
                        {new Date(
                          currentStatus.created_at,
                        ).toLocaleTimeString()}
                      </span>
                    </div>
                  </div>
                )}

                {/* Report Form */}
                {showReportForm && (
                  <form
                    onSubmit={handleSubmitReport}
                    className="bg-blue-50 rounded-lg p-4 mb-4"
                  >
                    <h3 className="font-medium mb-3">
                      Report Current Situation
                    </h3>

                    <div className="space-y-3">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Crowd Level
                        </label>
                        <select
                          value={reportData.crowd_level}
                          onChange={(e) =>
                            setReportData({
                              ...reportData,
                              crowd_level: e.target.value,
                            })
                          }
                          className="w-full p-2 border rounded-lg"
                          required
                        >
                          <option value="quiet">😊 Quiet (No wait)</option>
                          <option value="moderate">
                            😐 Moderate (5-15 min)
                          </option>
                          <option value="busy">😕 Busy (15-30 min)</option>
                          <option value="very_busy">
                            😫 Very Busy (30+ min)
                          </option>
                        </select>
                      </div>

                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Wait Time (minutes)
                        </label>
                        <input
                          type="number"
                          min="0"
                          max="180"
                          value={reportData.wait_time}
                          onChange={(e) =>
                            setReportData({
                              ...reportData,
                              wait_time: parseInt(e.target.value),
                            })
                          }
                          className="w-full p-2 border rounded-lg"
                          required
                        />
                      </div>

                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Your Name (optional)
                        </label>
                        <input
                          type="text"
                          value={reportData.reporter_name}
                          onChange={(e) =>
                            setReportData({
                              ...reportData,
                              reporter_name: e.target.value,
                            })
                          }
                          className="w-full p-2 border rounded-lg"
                          placeholder="Anonymous"
                        />
                      </div>

                      <div className="flex gap-2 pt-2">
                        <button
                          type="submit"
                          className="flex-1 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 transition"
                        >
                          Submit Report
                        </button>
                        <button
                          type="button"
                          onClick={() => setShowReportForm(false)}
                          className="px-4 py-2 border rounded-lg hover:bg-gray-50 transition"
                        >
                          Cancel
                        </button>
                      </div>
                    </div>
                  </form>
                )}

                {/* Recent Reports */}
                <div>
                  <h3 className="font-medium mb-3">
                    Recent Reports from This Location
                  </h3>
                  <div className="space-y-3 max-h-96 overflow-y-auto">
                    {reports.length === 0 ? (
                      <p className="text-gray-500 text-center py-4">
                        No reports yet. Be the first to report!
                      </p>
                    ) : (
                      reports.map((report) => (
                        <div key={report.id} className="border rounded-lg p-3">
                          <div className="flex justify-between items-start">
                            <div>
                              <div className="flex items-center gap-2 mb-2">
                                <span
                                  className={`px-2 py-0.5 rounded-full text-xs font-medium ${getCrowdColor(report.crowd_level)}`}
                                >
                                  {report.crowd_level.replace("_", " ")}
                                </span>
                                <span className="text-sm text-gray-600">
                                  Wait: {report.wait_time} min
                                </span>
                                {report.verified === 1 && (
                                  <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">
                                    ✓ Verified
                                  </span>
                                )}
                              </div>
                              <p className="text-xs text-gray-500">
                                Reported by {report.reporter_name} •{" "}
                                {new Date(report.created_at).toLocaleString()}
                              </p>
                            </div>
                            <button
                              onClick={() => handleVerifyReport(report.id)}
                              className="flex items-center gap-1 text-sm text-gray-600 hover:text-blue-600"
                            >
                              <ThumbsUp className="w-4 h-4" />
                              <span>{report.verification_count || 0}</span>
                            </button>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              </div>

              {/* Tips Card */}
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="font-medium mb-3 flex items-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-yellow-500" />
                  Tips for Accurate Reports
                </h3>
                <ul className="space-y-2 text-sm text-gray-600">
                  <li>
                    • Report only when you're at the location or have current
                    info
                  </li>
                  <li>
                    • Verify reports from others to build trust in the system
                  </li>
                  <li>
                    • Reports with 3+ verifications become "verified" status
                  </li>
                  <li>
                    • Best times to visit 26 Number Chungi: Late night (12 AM -
                    4 AM)
                  </li>
                </ul>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t mt-12">
        <div className="container mx-auto px-4 py-6">
          <p className="text-center text-gray-600 text-sm">
            ⚡ Community-powered M-Tag rush checker • Data refreshes every 60
            seconds
          </p>
        </div>
      </footer>
    </div>
  );
}

export default App;
